import{_ as t,H as e,f as r,i}from"./chunks/framework.Cvt1eIE0.js";const s="/store-locator/images/managed-storefront-page.png",a="/store-locator/images/theme-section.png",n="/store-locator/images/floating-widget.png",S=JSON.parse('{"title":"发布定位器 (Publish Store Locator)","description":"","frontmatter":{},"headers":[],"relativePath":"store-locator/guide/publish-locator.md","filePath":"store-locator/guide/publish-locator.md"}'),l={name:"store-locator/guide/publish-locator.md"};function g(d,o,c,p,h,m){return e(),r("div",null,[...o[0]||(o[0]=[i('<h1 id="发布定位器-publish-store-locator" tabindex="-1">发布定位器 (Publish Store Locator) <a class="header-anchor" href="#发布定位器-publish-store-locator" aria-label="Permalink to &quot;发布定位器 (Publish Store Locator)&quot;">​</a></h1><p>在 Jika Store Locator 中，您可以根据店铺的实际需求，灵活选择 3 种不同的发布模式。所有的发布选项都可以在应用后台的 <strong>Publish Options</strong> 中找到。</p><h2 id="mode-1-managed-storefront-page-独立页面" tabindex="-1">Mode 1: Managed Storefront Page (独立页面) <a class="header-anchor" href="#mode-1-managed-storefront-page-独立页面" aria-label="Permalink to &quot;Mode 1: Managed Storefront Page (独立页面)&quot;">​</a></h2><p>如果您想要一个快速、自动生成的专属地图页面，这是最简单的选择。 <img src="'+s+'" alt="创建页面"></p><ol><li>进入后台首页，点击 <strong>Publish Options</strong> 或左侧菜单的 <strong>Publish</strong>。</li><li>填写 <strong>Page Title (页面标题)</strong>。</li><li>从下方的 <strong>Select Layout Style</strong> 中选择一种页面布局（支持 Classic 经典左右分栏 和 Stacked 堆叠布局）。</li><li>点击 <strong>Create Storefront Page (创建店面页面)</strong>。</li><li>系统会自动在您的 Shopify 在线商店中创建一个新的独立页面。您可以通过点击 <strong>View Live</strong> 随时查看效果。</li></ol><h2 id="mode-2-theme-section-主题区块" tabindex="-1">Mode 2: Theme Section (主题区块) <a class="header-anchor" href="#mode-2-theme-section-主题区块" aria-label="Permalink to &quot;Mode 2: Theme Section (主题区块)&quot;">​</a></h2><p>如果您可以将地图随意嵌入任何页面，或者希望使用更丰富的布局引擎，请选择此模式。 <img src="'+a+'" alt="创建section"></p><ol><li>在 Publish 页面，找到 <strong>Mode 2: Theme Section</strong>。</li><li>点击 <strong>Open Theme Editor</strong> 按钮，跳转到 Shopify 主题编辑器。</li><li>在目标页面的左侧侧边栏中点击 <strong>Add section (添加区块)</strong>。</li><li>在 <strong>Apps (应用)</strong> 列表中，选择 <strong>Jika Store Locator</strong>。</li><li>此模式支持全量 <strong>9 种布局风格</strong>（包括 Floating、Modern、Minimal 等），您可以直接在主题编辑器的右侧面板中进行切换和配置。</li><li>点击右上角的 <strong>Save (保存)</strong>。</li></ol><h2 id="mode-3-floating-widget-悬浮挂件" tabindex="-1">Mode 3: Floating Widget (悬浮挂件) <a class="header-anchor" href="#mode-3-floating-widget-悬浮挂件" aria-label="Permalink to &quot;Mode 3: Floating Widget (悬浮挂件)&quot;">​</a></h2><p>悬浮小组件是一个强大的功能，它会在您店铺的每个页面角落放置一个悬浮按钮。点击后，会在优雅的弹窗中打开门店定位器，让客户无需离开当前页面即可查找门店。 <img src="'+n+'" alt="悬浮组建"></p><p><strong>开启挂件需要双重验证：</strong></p><ol><li>在 Publish 页面的 Mode 3 下，点击 <strong>Configure Widget</strong>，跳转到 <strong>Settings &gt; Widget Settings</strong>。</li><li>在 Widget Activation 卡片中，确保勾选了 <strong>Enable Floating Widget (启用悬浮挂件)</strong> 开关。</li><li>接着，点击 <strong>Go to Theme Editor</strong> 进入 Shopify 主题编辑器。</li><li>在左侧栏最底部的 <strong>App embeds (应用嵌入)</strong> 设置中，找到 <strong>Jika Store Locator Widget</strong> 并将其开启。</li><li>点击右上角的 <strong>Save (保存)</strong>。</li></ol><p>挂件的按钮位置、颜色和弹窗布局都可以随时在应用的 <strong>Widget Settings</strong> 中进行调整。</p>',13)])])}const _=t(l,[["render",g]]);export{S as __pageData,_ as default};
